### **3. Expansion/Contraction Rules**

```javascript
const transformRules = {
  expand: {
    // When expanding, what gets added?
    claim: {
      5 → 8: ['add_supporting_stat', 'add_context'],
      8 → 10: ['add_counterpoint', 'add_example']
    },
    support: {
      5 → 8: ['add_evidence', 'add_quote'],
      8 → 10: ['add_case_study', 'add_data_viz']
    }
  },

  contract: {
    // When contracting, what's essential?
    claim: {
      5 → 2: ['keep_core_assertion', 'drop_qualifiers'],
      2 → 0: ['keep_subject+verb only']
    },
    support: {
      5 → 2: ['keep_strongest_evidence', 'drop_examples'],
      2 → 0: ['drop_entirely']
    }
  }
};
```

