### **4. Semantic Preservation Score**

```javascript
function calculateSemanticIntegrity(original, transformed) {
  return {
    // Core meaning preserved (0-1)
    fidelity: cosineSimilarity(embed(original), embed(transformed)),

    // Structural balance maintained (all nodes present proportionally)
    balance: checkNodeRatios(transformed),

    // Information density (bits per char)
    density: entropy(transformed) / transformed.length,

    // Readability at this scale
    clarity: fleschKincaid(transformed)
  };
}
```

---

### **5. Merge Strategy**

```javascript
const mergeStrategies = {
  // When combining variants at different detail levels
  upscale: (lowDetail, highDetail) => {
    // Take structure from low, details from high
    const skeleton = extractNodes(lowDetail);
    const flesh = extractDetails(highDetail);
    return combine(skeleton, flesh);
  },

  // When combining same-level variants with different content
  blend: (variantA, variantB) => {
    // Weighted average based on acceptance history
    const scoreA = memory.getAcceptanceRate(variantA);
    const scoreB = memory.getAcceptanceRate(variantB);
    return weightedMerge(variantA, variantB, scoreA, scoreB);
  },

  // When user explicitly chooses
  cherryPick: (variants, userSelections) => {
    return userSelections.map(sel => 
      extractNode(variants[sel.variantId], sel.nodeType)
    ).join(' ');
  }
};
```

